//! FLUX VAE decoder forward PoC on SYNTHETIC weights — emits a REAL PNG.
//!
//! The marquee FLUX txt2img pipeline is T5/CLIP conditioning → MMDiT velocity
//! → flow-match denoise → AutoencoderKL decode → PNG. The decode stage is the
//! one that literally turns latents into pixels. The real run needs the
//! 17.9 GB `flux-1-schnell.knot` (12.6 GB of which is the DiT, served zero-copy
//! only from a LOCAL mmap), which does not fit this box with margin (16 GB RAM,
//! ~21 GB free disk → a download would leave <4 GB, under the safety floor; the
//! full DiT held resident over HTTP would OOM 16 GB).
//!
//! So, mirroring `glm-ocr-synth-poc`, this proves the REAL VAE decoder kernel
//! (`model_flux_mmdit::FluxVae`) end-to-end at REAL FLUX dims using a small
//! (~200 MB) but STRUCTURALLY COMPLETE synthetic FLUX-VAE knot (see
//! `flux_vae_synth`). Only the weight VALUES are synthetic; the kernel path,
//! tensor shapes, Q8_0 attention linears, GroupNorm groups, conv padding, and
//! the unscale/clamp are the production ones. The gate asserts the VAE loads,
//! decode runs, output is correctly sized, all-finite, and non-degenerate. The
//! PNG is a REAL image from the REAL decoder — FORWARD-PROVEN, NOT prompt-faithful.
//!
//! Usage:
//!   flux-vae-synth-poc [--latent 32] [--seed 42] [--output out.png] [--keep-knot]

use std::time::Instant;

use distributed_inference::flux_vae_synth::{gaussian, write_synthetic_flux_vae_knot};
use distributed_inference::loader::KnotWeights;
use distributed_inference::model_flux_mmdit::{FluxVae, FLUX_LATENT_CHANNELS};
use image::{Rgba, RgbaImage};

struct Args {
    latent: usize,
    seed: u64,
    output: String,
    keep_knot: bool,
}

fn parse_args() -> Args {
    let mut a = Args {
        latent: 32, // 32 → 256×256 output (×8)
        seed: 42,
        output: "/tmp/flux-vae-synth-poc.png".to_string(),
        keep_knot: false,
    };
    let raw: Vec<String> = std::env::args().skip(1).collect();
    let mut i = 0;
    while i < raw.len() {
        let need = |i: usize| -> &String {
            raw.get(i + 1).unwrap_or_else(|| {
                eprintln!("missing value for {}", raw[i]);
                std::process::exit(2);
            })
        };
        match raw[i].as_str() {
            "--latent" => {
                a.latent = need(i).parse().unwrap();
                i += 2;
            }
            "--seed" => {
                a.seed = need(i).parse().unwrap();
                i += 2;
            }
            "--output" => {
                a.output = need(i).clone();
                i += 2;
            }
            "--keep-knot" => {
                a.keep_knot = true;
                i += 1;
            }
            "-h" | "--help" => {
                eprintln!("usage: flux-vae-synth-poc [--latent N] [--seed N] [--output P] [--keep-knot]");
                std::process::exit(0);
            }
            other => {
                eprintln!("unknown arg {other}");
                std::process::exit(2);
            }
        }
    }
    a
}

fn main() {
    let args = parse_args();
    let (lh, lw) = (args.latent, args.latent);
    let (out_h, out_w) = (lh * 8, lw * 8);

    eprintln!("flux-vae-synth-poc: SYNTHETIC weights (no knot) — REAL FluxVae decoder kernel");
    eprintln!("  latent: [{FLUX_LATENT_CHANNELS}, {lh}, {lw}]  →  image {out_w}x{out_h} (×8 VAE)");

    let t_build = Instant::now();
    let knot_path = std::env::temp_dir().join(format!("flux-vae-synth-{}.knot", std::process::id()));
    let n_tensors = write_synthetic_flux_vae_knot(&knot_path).expect("write synthetic knot");
    let knot_mb = std::fs::metadata(&knot_path).map(|m| m.len()).unwrap_or(0) as f64 / 1e6;
    eprintln!(
        "  synthetic knot: {n_tensors} tensors, {knot_mb:.1} MB → {} in {:?}",
        knot_path.display(),
        t_build.elapsed(),
    );

    let cleanup = |keep: bool| {
        if !keep {
            let _ = std::fs::remove_file(&knot_path);
        }
    };

    let knot_source = knot_path.to_str().expect("utf8 knot path");
    let t_load = Instant::now();
    let knot: KnotWeights = match KnotWeights::load(knot_source) {
        Ok(k) => k,
        Err(e) => {
            eprintln!("FAIL: KnotWeights::load: {e}");
            cleanup(args.keep_knot);
            std::process::exit(1);
        }
    };
    let vae = match FluxVae::load(knot_source, &knot) {
        Ok(v) => v,
        Err(e) => {
            eprintln!("FAIL: FluxVae::load: {e}");
            cleanup(args.keep_knot);
            std::process::exit(1);
        }
    };
    eprintln!("  FluxVae loaded in {:?}", t_load.elapsed());

    let mut st = args.seed ^ 0x9E37_79B9_7F4A_7C15;
    let mut latents = vec![0.0f32; FLUX_LATENT_CHANNELS * lh * lw];
    for v in latents.iter_mut() {
        *v = gaussian(&mut st);
    }

    let t_dec = Instant::now();
    let rgb = match vae.decode(&latents, lh, lw) {
        Ok(r) => r,
        Err(e) => {
            eprintln!("FAIL: FluxVae::decode: {e}");
            cleanup(args.keep_knot);
            std::process::exit(1);
        }
    };
    let dec_dt = t_dec.elapsed();
    cleanup(args.keep_knot);

    let n_pixels = out_h * out_w;
    if rgb.len() != n_pixels * 3 {
        eprintln!("FAIL: rgb length {} != expected {}", rgb.len(), n_pixels * 3);
        std::process::exit(1);
    }
    let mut luma = Vec::with_capacity(n_pixels);
    let mut distinct = std::collections::HashSet::new();
    for p in 0..n_pixels {
        let (r, g, b) = (rgb[p * 3], rgb[p * 3 + 1], rgb[p * 3 + 2]);
        luma.push(0.299 * r as f32 + 0.587 * g as f32 + 0.114 * b as f32);
        distinct.insert((r, g, b));
    }
    let lmean = luma.iter().sum::<f32>() / luma.len() as f32;
    let luma_std =
        (luma.iter().map(|x| (x - lmean) * (x - lmean)).sum::<f32>() / luma.len() as f32).sqrt();

    let mut image = RgbaImage::new(out_w as u32, out_h as u32);
    for y in 0..out_h {
        for x in 0..out_w {
            let p = y * out_w + x;
            image.put_pixel(
                x as u32,
                y as u32,
                Rgba([rgb[p * 3], rgb[p * 3 + 1], rgb[p * 3 + 2], 255]),
            );
        }
    }
    image.save(&args.output).expect("write PNG");

    println!("\n── flux-vae-synth-poc result ──");
    println!("  output PNG:      {}", args.output);
    println!("  dimensions:      {out_w}x{out_h}");
    println!("  decode wall:     {dec_dt:.2?}");
    println!("  luma mean/std:   {lmean:.2} / {luma_std:.2}");
    println!("  distinct colors: {}/{}", distinct.len(), n_pixels);

    // decode() returns Err on any non-finite, so reaching here ⇒ finite.
    let size_ok = rgb.len() == n_pixels * 3;
    let nondegen_ok = luma_std > 1.0 && distinct.len() > (n_pixels / 100).max(16);
    if size_ok && nondegen_ok {
        println!(
            "\nPASS: FLUX VAE decoder ran end-to-end on synthetic weights at real dims \
             (real kernel path; finite, non-degenerate PNG). FORWARD-PROVEN, not prompt-faithful."
        );
        std::process::exit(0);
    }
    println!("\nFAIL: size_ok={size_ok} nondegen_ok={nondegen_ok}");
    std::process::exit(1);
}
